 3→export function columnOutline(column) {
 4→  const hw = column.width / 2, hd = column.depth / 2;
 5→  const { x: cx, y: cy } = column;
 6→  const corners = [
 7→    { x: cx - hw, y: cy - hd }, { x: cx + hw, y: cy - hd },
 8→    { x: cx + hw, y: cy + hd }, { x: cx - hw, y: cy + hd },
 9→  ];
10→  if (!column.rotation) return corners;
11→  return corners.map(p => rotate(p, { x: cx, y: cy }, column.rotation));
12→}
13→
14→export function columnSnapPoints(column) {
15→  return [{ x: column.x, y: column.y }, ...columnOutline(column)];
16→}
