  1→import { createWall } from '@/domain/models';
  2→import { distance } from '@/geometry/point';
  3→import { nearestPointOnSegment } from '@/geometry/line';
  4→import { SNAP_DISTANCE_PX, MIN_WALL_LENGTH } from '@/domain/defaults';
  5→import { columnSnapPoints } from '@/geometry/columnGeometry';
  6→
  7→function snapToWalls(modelPos, walls, snapDistModel, chainStart, columns) {
  8→  let best = null;
  9→  let bestDist = snapDistModel;
 10→
 11→  // Snap to chain start to close loop (highest priority)
 12→  if (chainStart) {
 13→    const d = distance(modelPos, chainStart);
 14→    if (d < bestDist) {
 15→      best = chainStart;
 16→      bestDist = d;
 17→    }
 18→  }
 19→
 20→  // Snap to wall endpoints
 21→  for (const wall of walls) {
 22→    for (const pt of [wall.start, wall.end]) {
 23→      const d = distance(modelPos, pt);
 24→      if (d < bestDist) {
 25→        best = pt;
 26→        bestDist = d;
 27→      }
 28→    }
 29→  }
 30→
 31→  // Snap to column points (center + corners)
 32→  for (const column of (columns || [])) {
 33→    for (const pt of columnSnapPoints(column)) {
 34→      const d = distance(modelPos, pt);
 35→      if (d < bestDist) {
 36→        best = pt;
 37→        bestDist = d;
 38→      }
 39→    }
 40→  }
 41→
 42→  // If no endpoint found, try snapping to nearest point on wall segments
 43→  if (!best) {
 44→    for (const wall of walls) {
 45→      const { point, t } = nearestPointOnSegment(modelPos, wall.start, wall.end);
 46→      if (t <= 0.001 || t >= 0.999) continue; // too close to endpoints, already covered
 47→      const d = distance(modelPos, point);
 48→      if (d < bestDist) {
 49→        best = point;
 50→        bestDist = d;
 51→      }
 52→    }
 53→  }
 54→
 55→  return best;
 56→}
