 58→function constrainAngle(start, end, shiftHeld) {
 59→  if (!shiftHeld) return end;
 60→  const dx = end.x - start.x;
 61→  const dy = end.y - start.y;
 62→  const angle = Math.atan2(dy, dx);
 63→  const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
 64→  const len = Math.sqrt(dx * dx + dy * dy);
 65→  return {
 66→    x: start.x + Math.cos(snapAngle) * len,
 67→    y: start.y + Math.sin(snapAngle) * len,
 68→  };
 69→}
