 1→export function signedPolygonArea(points) {
 2→  let area = 0;
 3→  const n = points.length;
 4→  for (let i = 0; i < n; i++) {
 5→    const j = (i + 1) % n;
 6→    area += points[i].x * points[j].y;
 7→    area -= points[j].x * points[i].y;
 8→  }
 9→  return area / 2;
10→}
11→
12→export function polygonArea(points) {
13→  let area = 0;
14→  const n = points.length;
15→  for (let i = 0; i < n; i++) {
16→    const j = (i + 1) % n;
17→    area += points[i].x * points[j].y;
18→    area -= points[j].x * points[i].y;
19→  }
20→  return Math.abs(area) / 2;
21→}
22→
23→export function polygonCentroid(points) {
24→  let cx = 0, cy = 0;
25→  const n = points.length;
26→  for (let i = 0; i < n; i++) {
27→    cx += points[i].x;
28→    cy += points[i].y;
29→  }
30→  return { x: cx / n, y: cy / n };
31→}
32→
33→export function pointInPolygon(point, polygon) {
34→  let inside = false;
35→  const n = polygon.length;
36→  for (let i = 0, j = n - 1; i < n; j = i++) {
37→    const xi = polygon[i].x, yi = polygon[i].y;
38→    const xj = polygon[j].x, yj = polygon[j].y;
39→    if (
40→      yi > point.y !== yj > point.y &&
41→      point.x < ((xj - xi) * (point.y - yi)) / (yj - yi) + xi
42→    ) {
43→      inside = !inside;
44→    }
45→  }
46→  return inside;
47→}
