 6→const WALL_DETECT_RADIUS = 500; // mm
 7→
 8→function findNearestWall(modelPos, walls) {
 9→  let best = null;
10→  let bestDist = WALL_DETECT_RADIUS;
11→
12→  for (const wall of walls) {
13→    const d = distanceToSegment(modelPos, wall.start, wall.end);
14→    if (d < bestDist) {
15→      best = wall;
16→      bestDist = d;
17→    }
18→  }
19→  return best;
20→}
