42→export function createDoorPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId }) {
43→  return {
44→    onMouseMove(modelPos, e, toolState) {
45→      const floor = getFloor(activeFloorId);
46→      const wall = findNearestWall(modelPos, floor.walls);
47→
48→      if (wall) {
49→        const offset = projectPointOnWall(wall, modelPos);
50→        const halfWidth = DOOR_WIDTH / 2;
51→        const maxOffset = wallLength(wall) - halfWidth;
52→        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, offset));
53→        const blocked = overlapsExisting(wall.id, clampedOffset, DOOR_WIDTH, floor.doors, floor.windows);
54→
55→        editorDispatch({
56→          type: 'UPDATE_TOOL_STATE',
57→          payload: {
58→            previewWallId: wall.id,
59→            previewOffset: clampedOffset,
60→            previewBlocked: blocked,
61→          },
62→        });
63→      } else {
64→        editorDispatch({
65→          type: 'UPDATE_TOOL_STATE',
66→          payload: { previewWallId: null, previewOffset: null, previewBlocked: false },
67→        });
68→      }
69→    },
70→
71→    onMouseDown(modelPos, e, toolState) {
72→      if (e.button !== 0) return;
73→      if (!toolState.previewWallId || toolState.previewBlocked) return;
74→
75→      const door = createDoor(toolState.previewWallId, toolState.previewOffset);
76→      dispatch({ type: 'DOOR_ADD', floorId: activeFloorId, door });
77→    },
78→
79→    onKeyDown(e, toolState) {
80→      if (e.key === 'Escape') {
81→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
82→      }
83→    },
84→
85→    getCursor(toolState) {
86→      if (!toolState.previewWallId || toolState.previewBlocked) return 'not-allowed';
87→      return 'copy';
88→    },
89→  };
90→}
